insert into public.products (
  id, category_id, name, brand, family, subtitle, description, plain_description, public_price, distributor_price, tax_note, sale_status, capacity, power, expansion, tags, image_url, source_url, specs
) values
  ('river-3', 'estaciones', 'RIVER 3', 'EcoFlow', 'Serie RIVER', 'Conectividad y emergencia básica', 'La opción más compacta para conservar comunicación, iluminación y carga de dispositivos durante un apagón corto.', 'Con este equipo puedes mantener módem/router y 2 celulares aprox. 7-9 h; si agregas una laptop eficiente, aprox. 2-3 h. Se recarga en aprox. 1 h conectado a la luz y en 2.5-3 h con panel solar de 110 W.', 5099, NULL, 'IVA incluido', 'Bajo pedido', '230 Wh', '300 W', 'No admite batería adicional', ARRAY['Módem y router', 'Celulares', 'Luces LED', 'Laptop eficiente']::text[], 'https://cdn.shopify.com/s/files/1/0593/6132/9231/files/ecoflow-us-ecoflow-river-3-portable-power-station-r3-1174069423.png?v=1756976053', 'https://mx.ecoflow.com/products/river-3-portable-power-station', '{"level":1,"category_original":"portatil","avoid":["Refrigerador durante muchas horas","Microondas","Cafetera potente","Aire acondicionado"],"keywords":"internet modem router celular luces laptop portátil emergencia"}'::jsonb),
  ('river-3-ups', 'estaciones', 'RIVER 3 UPS', 'EcoFlow', 'Serie RIVER', 'Continuidad para equipos sensibles', 'Mantiene conectados equipos sensibles durante cortes breves y está enfocada en funcionar como respaldo UPS. Frente a la RIVER 3 convencional no ofrece más potencia: su diferencia principal es la continuidad para módem, computadora, NAS o CPAP.', 'Con este equipo mantienes módem/router o una computadora eficiente sin que se apague en cortes cortos: 7-9 h con internet, 2-3 h con laptop y 1-2 h con dos equipos sensibles. Carga aprox. 1 h a la luz y 2.5-3 h con solar.', 5119, NULL, 'IVA incluido', 'Bajo pedido', '245 Wh', '300 W', 'No admite batería adicional', ARRAY['Módem y router', 'Computadora eficiente', 'NAS', 'CPAP', 'Luces LED']::text[], 'https://cdn.shopify.com/s/files/1/0593/6132/9231/files/ecoflow-us-ecoflow-river-3-portable-power-station-r3-1174069423.png?v=1756976053', 'https://mx.ecoflow.com/products/river-3-portable-power-station', '{"level":1,"category_original":"portatil","avoid":["Microondas","Cafetera potente","Refrigerador durante muchas horas","Aire acondicionado"],"keywords":"ups no break respaldo modem router computadora nas cpap continuidad corte breve 245wh 300w","price_source":"Excel base_datos_powerme_comercial_integrada_precios_completos.xlsx","price_source_row_id":"P0053","price_match_score":1}'::jsonb),
  ('river-3-plus', 'estaciones', 'RIVER 3 Plus', 'EcoFlow', 'Serie RIVER', 'Home office compacto', 'Entrega más potencia que la RIVER 3 y permite agregar una batería compatible cuando se necesita mayor duración.', 'Con este equipo puedes sostener módem/router y laptop aprox. 3-4 h; si agregas monitor, calcula 2-3 h. Se recarga en aprox. 1 h a la luz y 1.5-2 h con panel solar compatible; con batería extra aumenta la autonomía.', 5999, NULL, 'IVA incluido', 'Bajo pedido', '268 Wh', '600 W', 'Sí: EB300 o EB600; hasta aprox. 840 Wh', ARRAY['Módem y router', 'Laptop', 'Monitor', 'Celulares', 'TV pequeña']::text[], 'https://cdn.shopify.com/s/files/1/0593/6132/9231/files/ecoflow-us-ecoflow-river-3-plus-portable-power-station-standalone-36158995398729.png?v=1752041545', 'https://mx.ecoflow.com/products/river-3-plus-portable-power-station', '{"level":2,"category_original":"portatil","avoid":["Circuitos de casa","Bombas grandes","Minisplit","Cocina eléctrica"],"keywords":"home office laptop monitor internet televisión batería adicional"}'::jsonb),
  ('river-2-max', 'estaciones', 'RIVER 2 Max', 'EcoFlow', 'Serie RIVER', 'Autonomía media para trabajo y entretenimiento', 'Ofrece aproximadamente el doble de energía que una RIVER compacta para trabajar, ver televisión o usar un ventilador durante más tiempo. Su capacidad es parecida a la RIVER 3 Max, pero entrega menos potencia: 500 W frente a 600 W.', 'Con este equipo puedes mantener home office básico 5-7 h, TV 4-5 h o módem/router más laptop 6-8 h. Con dos equipos medianos calcula 3-4 h. Se recarga en aprox. 1 h a la luz y 3-4 h con solar.', 9999, NULL, 'IVA incluido', 'Bajo pedido', '512 Wh', '500 W', 'No admite batería adicional', ARRAY['Home office', 'Laptop y monitor', 'Internet', 'Televisión', 'Ventilador']::text[], 'https://cdn.shopify.com/s/files/1/0593/6132/9231/files/ecoflow-us-ecoflow-river-2-max-portable-power-station-30042740555849_1500x_d4588403-9891-493c-a7c9-990bda1498dd.webp?v=1762658410', 'https://mx.ecoflow.com/products/river-2-max-500-portable-power-station', '{"level":3,"category_original":"homeoffice","avoid":["Microondas potente","Bomba","Minisplit","Circuitos completos"],"keywords":"home office 512wh 500w laptop monitor television ventilador internet river 2 max"}'::jsonb),
  ('river-3-max', 'estaciones', 'RIVER 3 Max', 'EcoFlow', 'Serie RIVER', 'Jornada de trabajo con batería ampliada', 'Es una RIVER 3 Plus acompañada por la batería EB300. Aumenta la duración, pero conserva 600 W de potencia de salida.', 'Con este equipo puedes trabajar con módem/router, laptop y monitor aprox. 6-8 h; con TV o ventilador, 5-7 h. Con dos equipos medianos calcula 3-5 h. Se recarga en aprox. 1.5 h a la luz y 3-4 h con solar.', 10199, NULL, 'IVA incluido', 'Bajo pedido', '554 Wh', '600 W', 'Ya incluye una batería EB300', ARRAY['Jornada de home office', 'Laptop y monitor', 'Internet', 'TV', 'Ventilador']::text[], 'https://cdn.shopify.com/s/files/1/0593/6132/9231/files/ecoflow-us-ecoflow-river-3-plus-portable-power-station-standalone-35888815702089_85b7f2bf-3fb2-4570-874e-870566788373.png?v=1775123729', 'https://mx.ecoflow.com/products/river-3-max-river-3-plus-extra-battery-300', '{"level":3,"category_original":"homeoffice","avoid":["Microondas grande","Bomba","Minisplit","Circuitos completos"],"keywords":"jornada oficina laptop monitor ventilador televisión internet"}'::jsonb),
  ('river-2-pro', 'estaciones', 'RIVER 2 Pro', 'EcoFlow', 'Serie RIVER', 'Más potencia portátil dentro de la serie RIVER', 'Combina 768 Wh con una salida de 800 W, por lo que puede alimentar aparatos más exigentes que la RIVER 2 Max y las RIVER 3 de 600 W. Comparada con la RIVER 3 Max Plus, almacena un poco menos de energía, pero entrega más potencia.', 'Con este equipo puedes usar laptop, router y monitor 8-10 h; TV o ventilador 7-9 h, y un refrigerador eficiente por periodos controlados. Con dos equipos medianos calcula 4-6 h. Carga aprox. 1.2 h a la luz y 4-5 h con solar.', 9999, NULL, 'IVA incluido', 'Bajo pedido', '768 Wh', '800 W', 'No admite batería adicional', ARRAY['Home office exigente', 'Televisión', 'Ventilador', 'Refrigerador eficiente temporal', 'Aparatos de hasta 800 W']::text[], 'https://cdn.shopify.com/s/files/1/0593/6132/9231/files/ecoflow-us-ecoflow-river-2-pro-portable-power-station-30042784006217_1500x_0df8c4aa-09a0-4fc7-b463-e0dc0623a685.webp?v=1733970158', 'https://mx.ecoflow.com/products/river-2-pro-portable-power-station', '{"level":3,"category_original":"homeoffice","avoid":["Toda la casa","Minisplit","Calentadores prolongados","Equipos de 240 V"],"keywords":"river 2 pro 768wh 800w xboost 1600 home office refrigerador television ventilador potencia","price_source":"Excel base_datos_powerme_comercial_integrada_precios_completos.xlsx","price_source_row_id":"P0049","price_match_score":1}'::jsonb),
  ('river-3-max-plus', 'estaciones', 'RIVER 3 Max Plus', 'EcoFlow', 'Serie RIVER', 'Mayor autonomía dentro de la familia RIVER', 'Es la configuración RIVER con mayor capacidad. Está pensada para electrónica y consumos moderados durante más horas.', 'Con este equipo puedes mantener home office completo 9-12 h, TV/ventilador 8-10 h o refrigerador eficiente por periodos más largos. Con dos equipos medianos calcula 5-7 h. Carga aprox. 2-2.5 h a la luz y 5-6 h con solar.', 17400, NULL, 'IVA incluido', 'Bajo pedido', '840 Wh', '600 W', 'Ya incluye una batería EB600', ARRAY['Home office prolongado', 'Internet', 'TV', 'Ventilador', 'Refrigerador temporal']::text[], 'https://cdn.shopify.com/s/files/1/0593/6132/9231/files/ecoflow-us-ecoflow-river-3-plus-portable-power-station-standalone-35888815669321_85f32f34-63f6-4830-8f25-391020407b37.png?v=1752564431', 'https://mx.ecoflow.com/products/river-3-max-plus-river-3-plus-extra-battery-600', '{"level":3,"category_original":"homeoffice","avoid":["Toda la casa","Aire acondicionado","Bomba grande","Equipos de 240 V"],"keywords":"larga duración refrigerador temporal laptop monitor televisión ventilador","price_source":"Excel base_datos_powerme_comercial_integrada_precios_completos.xlsx","price_source_row_id":"P0023","price_match_score":0.8}'::jsonb),
  ('delta-2-black', 'estaciones', 'DELTA 2 Black', 'EcoFlow', 'Serie DELTA', 'Casi 1 kWh para cargas moderadas', 'Almacena casi la misma energía que una DELTA 3, pero su salida es mucho menor: 500 W frente a 1,800 W. Por eso ofrece buena duración con internet, computadoras, televisión y refrigeradores eficientes cuyo arranque sea compatible, pero no es la indicada para aparatos de alto consumo.', 'Con este equipo puedes mantener internet, cámaras y TV muchas horas: 12-18 h con cargas pequeñas, 6-8 h con dos equipos medianos o un refrigerador eficiente controlado. Carga aprox. 1.5 h a la luz y 3-4 h con solar.', 11939.66, NULL, '', 'Bajo pedido', '980 Wh', '500 W', 'Capacidad fija de 980 Wh', ARRAY['Internet y computadoras', 'Televisión', 'Luces', 'Cámaras', 'Refrigerador eficiente verificado']::text[], 'https://mx.ecoflow.com/cdn/shop/files/e980_a21252ea-2bab-41c4-819c-fddd2c67a79a.png?v=1762845476', 'https://mx.ecoflow.com/products/ecoflow-power-station-delta-2-black-e980', '{"level":3,"category_original":"hogar","avoid":["Microondas","Cafetera potente","Parrilla eléctrica","Secadora de cabello","Aire acondicionado"],"keywords":"delta 2 black e980 980wh 500w ups 30ms internet computadoras television refrigerador eficiente","display_price":"$11,939.66"}'::jsonb),
  ('delta-3', 'estaciones', 'DELTA 3', 'EcoFlow', 'Serie DELTA', 'Potencia DELTA en configuración sencilla', 'Entrega la misma capacidad y potencia base que la DELTA 3 Plus para refrigerador y electrodomésticos comunes. La diferencia es que la DELTA 3 es la opción más sencilla: admite hasta 500 W solares y no ofrece la expansión de batería de la versión Plus.', 'Con este equipo puedes mantener refrigerador, internet y algunas luces aprox. 6-10 h; microondas o cafetera conviene usarlos por periodos cortos. Con dos equipos medianos calcula 4-6 h. Carga aprox. 1 h a la luz y 2.5-3 h con solar.', 17240.52, NULL, '', 'Bajo pedido', '1,024 Wh', '1,800 W', 'Capacidad fija de 1,024 Wh', ARRAY['Refrigerador', 'Computadoras', 'Televisión', 'Cafetera', 'Licuadora', 'Microondas pequeño controlado']::text[], 'https://cdn.shopify.com/s/files/1/0593/6132/9231/files/ecoflow-us-ecoflow-delta-3-plus-portable-power-station-standalone-delta-3-plus-1179495741.png?v=1756975490', 'https://www.ecoflow.com/us/delta-3-portable-power-station', '{"level":4,"category_original":"hogar","avoid":["Toda la vivienda","Varios aires acondicionados","Calentadores durante horas"],"keywords":"delta 3 1024wh 1800w refrigerador hogar microondas cafetera solar 500w capacidad fija","display_price":"$17,240.52"}'::jsonb),
  ('delta-3-plus', 'estaciones', 'DELTA 3 Plus', 'EcoFlow', 'Serie DELTA', 'Respaldo equilibrado para hogar y oficina', 'Combina suficiente potencia para electrodomésticos comunes con una capacidad inicial de 1 kWh y opción de ampliación.', 'Con este equipo puedes mantener refrigerador, internet, TV y luces aprox. 6-10 h; con home office completo, 8-12 h. Con dos equipos medianos calcula 4-6 h. Carga aprox. 1 h a la luz y 1.5-2 h con buena entrada solar.', 21999, NULL, 'IVA incluido', 'Bajo pedido', '1,024 Wh', '1,800 W', 'Sí: batería inteligente compatible; hasta aprox. 5 kWh', ARRAY['Refrigerador', 'Internet', 'Luces', 'Televisión', 'Computadoras', 'Cafetera']::text[], 'https://cdn.shopify.com/s/files/1/0593/6132/9231/files/ecoflow-us-ecoflow-delta-3-plus-portable-power-station-standalone-delta-3-plus-1179495741.png?v=1756975490', 'https://mx.ecoflow.com/products/delta-3-plus-portable-power-station', '{"level":4,"category_original":"hogar","avoid":["Toda la vivienda sin control","Varios aires","Calentadores durante horas"],"keywords":"refrigerador hogar oficina cafetera computadoras electrodomésticos","price_source":"Excel base_datos_powerme_comercial_integrada_precios_completos.xlsx","price_source_row_id":"P0035","price_match_score":1}'::jsonb),
  ('delta-2-max', 'estaciones', 'DELTA 2 Max', 'EcoFlow', 'Serie DELTA', 'Cargas esenciales durante más tiempo', 'Ofrece el doble de batería que una DELTA de 1 kWh y permite añadir dos baterías para apagones prolongados.', 'Con este equipo puedes mantener refrigerador, internet, TV y luces aprox. 10-16 h; con oficina completa, 12-18 h. Con dos o tres equipos medianos calcula 7-10 h. Carga aprox. 1.3 h a la luz y 2.5-3 h con solar.', 26981.9, NULL, '', 'Bajo pedido', '2,048 Wh', '2,400 W', 'Sí: hasta 2 baterías; capacidad total de 6,144 Wh', ARRAY['Refrigerador', 'Oficina completa', 'TV', 'Ventiladores', 'Microondas', 'Pequeño negocio']::text[], 'https://cdn.shopify.com/s/files/1/0593/6132/9231/files/ecoflow-delta-2-max-portable-power-station-51305159590231.png?v=1718876774', 'https://mx.ecoflow.com/products/delta-2-max-portable-power-station', '{"level":5,"category_original":"hogar","avoid":["Toda la casa sin control","Varios minisplits","Calefacción eléctrica prolongada"],"keywords":"casa cargas esenciales oficina negocio refrigerador microondas electrodomésticos","display_price":"$26,981.90"}'::jsonb),
  ('delta-pro', 'estaciones', 'DELTA Pro', 'EcoFlow', 'Serie DELTA Pro', 'Alta autonomía residencial y profesional', 'Supera ampliamente a la DELTA 2 Max en duración y potencia, y puede respaldar electrodomésticos pesados, herramientas, una RV o circuitos prioritarios con la instalación adecuada. Frente a la DELTA Pro 3 tiene un poco menos de capacidad y salida, pero sigue siendo un sistema residencial escalable.', 'Con este equipo puedes respaldar refrigerador, congelador, internet, TV y bomba pequeña aprox. 12-20 h según uso; herramientas o microondas se usan por periodos. Con dos circuitos esenciales calcula 8-12 h. Carga aprox. 2.5-3 h a la luz y 3-6 h con solar.', 35799, NULL, '', 'Bajo pedido', '3,600 Wh', '3,600 W', 'Sí: hasta 2 baterías; 10.8 kWh por unidad', ARRAY['Circuitos prioritarios', 'Refrigerador y congelador', 'Bomba', 'Microondas', 'Herramientas', 'RV']::text[], 'https://cdn.shopify.com/s/files/1/0593/6132/9231/files/ecoflow-us-ecoflow-delta-pro-portable-power-station-dp-delta-pro-portable-power-station-1179495743.png?v=1756889795', 'https://mx.ecoflow.com/products/delta-pro-portable-power-station', '{"level":6,"category_original":"residencial","avoid":["Instalación improvisada","Toda la casa sin calcular cargas","Varios equipos de 240 V sin diseño"],"keywords":"delta pro 3600wh 3600w residencial casa bomba herramientas rv expansion 10.8kwh","display_price":"$35,799"}'::jsonb),
  ('delta-pro-3', 'estaciones', 'DELTA Pro 3', 'EcoFlow', 'Serie DELTA Pro', 'Respaldo residencial y equipos de alto consumo', 'Está diseñada para cargas residenciales, salida de 120/240 V y conexión a circuitos prioritarios mediante transferencia.', 'Con este equipo puedes alimentar circuitos prioritarios, refrigerador, bomba o minisplit eficiente varias horas: 10-18 h en cargas esenciales y 6-10 h con dos cargas fuertes moderadas. Carga aprox. 2.5-3 h a la luz y 2-4 h con solar según paneles.', 60999, NULL, '', 'Bajo pedido', '4,096 Wh', '4,000 W', 'Sí: 1 o 2 baterías; 8.2 o 12.3 kWh por unidad', ARRAY['Circuitos prioritarios', 'Refrigerador', 'Bomba', 'Minisplit', 'Equipos de 120/240 V']::text[], 'https://mx.ecoflow.com/cdn/shop/files/ecoflow-ecoflow-delta-pro-3-portable-power-station-31998254350409.png?v=1765856654', 'https://mx.ecoflow.com/products/delta-pro-3-portable-power-station', '{"level":6,"category_original":"residencial","avoid":["Instalación improvisada","Toda la casa sin calcular consumo","Varios aires grandes simultáneos"],"keywords":"residencial casa bomba minisplit 240v transferencia refrigerador circuitos","display_price":"$60,999"}'::jsonb),
  ('delta-pro-ultra', 'estaciones', 'DELTA Pro Ultra', 'EcoFlow', 'Serie DELTA Pro', 'Sistema escalable para respaldo integral', 'Es una plataforma residencial modular para alimentar múltiples circuitos, equipos grandes y sistemas automáticos de respaldo.', 'Con este sistema puedes respaldar desde circuitos esenciales hasta gran parte de la casa. En configuración base de 6 kWh, cargas esenciales pueden durar aprox. 18-30 h; con expansión crece por etapas. La carga por luz o solar depende del diseño instalado.', 110000, NULL, '', 'Bajo pedido', 'Desde 6 kWh', 'Desde 7,200 W', 'Sí: sistema modular de 6 a 90 kWh', ARRAY['Toda la casa', 'Varios circuitos', 'Aires acondicionados', '120/240 V', 'Transferencia automática']::text[], 'https://cdn.shopify.com/s/files/1/0593/6132/9231/files/ecoflow-ecoflow-delta-pro-ultra-whole-home-backup-power-ecoflow-delta-pro-ultra-32618370236489.png?v=1740542286', 'https://mx.ecoflow.com/products/delta-pro-ultra', '{"level":7,"category_original":"residencial","avoid":["Compra sin estudio de cargas","Instalación sin protecciones","Uso sin electricista"],"keywords":"casa completa aires acondicionados 240v panel automático respaldo total","display_price":"$110,000"}'::jsonb),
  ('panel-solar-ecoflow-110w', 'paneles', 'Panel Solar EcoFlow 110W', 'EcoFlow', 'Panel solar', 'Panel solar portátil', 'Panel plegable y fácil de mover para recargar estaciones RIVER o DELTA pequeñas. Es buena opción para camping, apagones cortos y mantener equipos básicos con apoyo solar.', 'Panel plegable y fácil de mover para recargar estaciones RIVER o DELTA pequeñas. Es buena opción para camping, apagones cortos y mantener equipos básicos con apoyo solar.', 4999, NULL, 'IVA incluido', 'Bajo pedido', '110W', '110W', NULL, ARRAY['solar', 'panel', 'carga']::text[], 'https://cdn.shopify.com/s/files/1/0593/6132/9231/files/1-1_6aa110ac-773d-4a95-9986-64ae39ff610c.jpg?v=1775126040', 'https://mx.ecoflow.com/products/110w-portable-solar-panel', '{}'::jsonb),
  ('panel-solar-160w', 'paneles', 'Panel Solar 160W', 'EcoFlow', 'Panel solar', 'Panel solar portátil', 'Panel portátil con mayor captación que uno compacto. Sirve para recargar estaciones medianas durante el día y extender autonomía en viajes, campo o respaldo en casa.', 'Panel portátil con mayor captación que uno compacto. Sirve para recargar estaciones medianas durante el día y extender autonomía en viajes, campo o respaldo en casa.', 5499, NULL, 'IVA incluido', 'Bajo pedido', '160W', '160W', NULL, ARRAY['solar', 'panel', 'carga']::text[], 'https://mx.ecoflow.com/cdn/shop/files/1_43b53d4e-33a7-4f96-bfe9-9d20499c06f0.jpg?v=1775126162', NULL, '{}'::jsonb),
  ('panel-solar-125w', 'paneles', 'Panel Solar 125W', 'EcoFlow', 'Panel solar', 'Panel solar portátil', 'Panel intermedio para quien necesita más carga que un panel chico, pero quiere seguir con algo ligero. Funciona bien con estaciones portátiles y uso ocasional.', 'Panel intermedio para quien necesita más carga que un panel chico, pero quiere seguir con algo ligero. Funciona bien con estaciones portátiles y uso ocasional.', 5299, NULL, 'IVA incluido', 'Bajo pedido', '125W', '125W', NULL, ARRAY['solar', 'panel', 'carga']::text[], 'https://mx.ecoflow.com/cdn/shop/files/imgi_286_71ftIGLOZDL_small.jpg?v=1775126438', NULL, '{}'::jsonb),
  ('panel-solar-ecoflow-400w', 'paneles', 'Panel Solar EcoFlow 400W', 'EcoFlow', 'Panel solar', 'Panel solar portátil', 'Panel portátil de alta potencia para cargar más rápido estaciones DELTA. Conviene cuando necesitas recuperar batería durante el día y aprovechar mejor las horas de sol.', 'Panel portátil de alta potencia para cargar más rápido estaciones DELTA. Conviene cuando necesitas recuperar batería durante el día y aprovechar mejor las horas de sol.', 14849, NULL, 'IVA incluido', 'Bajo pedido', '400W', '400W', NULL, ARRAY['solar', 'panel', 'carga']::text[], 'https://cdn.shopify.com/s/files/1/0593/6132/9231/files/ecoflow-400w-portable-solar-panel-42463116132516.png?v=1718876811', 'https://mx.ecoflow.com/products/400w-portable-solar-panel', '{}'::jsonb),
